import { pool, isDbConfigured } from './db';

export interface User {
    id: number;
    username: string;
    displayName: string;
    role: string;
}

export const login = async (username: string, password: string): Promise<User | null> => {
    if (!isDbConfigured) {
        throw new Error('DB_NOT_CONFIGURED');
    }

    try {
        // Note: In a real production app, passwords should be hashed (e.g., bcrypt).
        // This example uses plain text for demonstration purposes as per the SQL setup.
        const res = await pool.query(
            'SELECT id, username, display_name, role FROM public.users WHERE username = $1 AND password = $2',
            [username, password]
        );

        if (res.rows.length > 0) {
            const row = res.rows[0];

            // Check Role Constraint
            // Only allow 'admin' role to login. 'user' role must wait for approval.
            if (row.role !== 'admin') {
                throw new Error('WAITING_FOR_APPROVAL');
            }
            return {
                id: row.id,
                username: row.username,
                displayName: row.display_name,
                role: row.role,
            };
        } else {
            return null;
        }
    } catch (err) {
        console.error('Login error:', err);
        throw err;
    }
};

export const register = async (username: string, displayName: string, password: string): Promise<User> => {
    if (!isDbConfigured) {
        throw new Error('DB_NOT_CONFIGURED');
    }

    // Default 'user' role for new registrations as per requirements.
    const role = 'user';

    try {
        const res = await pool.query(
            'INSERT INTO public.users (username, display_name, password, role) VALUES ($1, $2, $3, $4) RETURNING id, username, display_name, role',
            [username, displayName, password, role]
        );
        const row = res.rows[0];
        return {
            id: row.id,
            username: row.username,
            displayName: row.display_name,
            role: row.role,
        };
    } catch (err) {
        console.error('Registration error:', err);
        throw err;
    }
};
```


